     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState, jjrg_Pace as Pace};
    13→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    14→use serde::Serialize;
    15→use std::fs;
    16→
    17→// ============================================================================
    18→// Muster - List all Heats with summary information
    19→// ============================================================================
    20→
    21→/// Arguments for muster command
    22→#[derive(Debug)]
    23→pub struct jjrq_MusterArgs {
    24→    pub file: std::path::PathBuf,
    25→}
    26→
    27→/// Run the muster command - list Heats as TSV
    28→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    29→    let gallops = match Gallops::jjrg_load(&args.file) {
    30→        Ok(g) => g,
    31→        Err(e) => {
    32→            eprintln!("jjx_muster: error: {}", e);
    33→            return 1;
    34→        }
    35→    };
    36→
    37→    for (key, heat) in &gallops.heats {
    38→        let pace_count = heat.paces.len();
    39→        let status_str = match heat.status {
    40→            HeatStatus::Racing => "racing",
    41→            HeatStatus::Stabled => "stabled",
    42→            HeatStatus::Retired => "retired",
    43→        };
    44→
    45→        println!("{}\t{}\t{}\t{}", key, heat.silks, status_str, pace_count);
    46→    }
    47→
    48→    0
    49→}
    50→
    51→// ============================================================================
    52→// Saddle - Return context needed to saddle up on a Heat
    53→// ============================================================================
    54→
    55→/// Arguments for saddle command
    56→#[derive(Debug)]
    57→pub struct jjrq_SaddleArgs {
    58→    pub file: std::path::PathBuf,
    59→    pub firemark: Firemark,
    60→}
    61→
    62→/// Output structure for saddle command
    63→#[derive(Serialize)]
    64→pub(crate) struct zjjrq_SaddleOutput {
    65→    pub(crate) heat_silks: String,
    66→    pub(crate) paddock_file: String,
    67→    pub(crate) paddock_content: String,
    68→    #[serde(skip_serializing_if = "Option::is_none")]
    69→    pub(crate) pace_coronet: Option<String>,
    70→    #[serde(skip_serializing_if = "Option::is_none")]
    71→    pub(crate) pace_silks: Option<String>,
    72→    #[serde(skip_serializing_if = "Option::is_none")]
    73→    pub(crate) pace_state: Option<String>,
    74→    #[serde(skip_serializing_if = "Option::is_none")]
    75→    pub(crate) spec: Option<String>,
    76→    #[serde(skip_serializing_if = "Option::is_none")]
    77→    pub(crate) direction: Option<String>,
    78→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
    79→}
    80→
    81→/// Run the saddle command - return Heat context
    82→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
    83→    let gallops = match Gallops::jjrg_load(&args.file) {
    84→        Ok(g) => g,
    85→        Err(e) => {
    86→            eprintln!("jjx_saddle: error: {}", e);
    87→            return 1;
    88→        }
    89→    };
    90→
    91→    let heat_key = args.firemark.jjrf_display();
    92→    let heat = match gallops.heats.get(&heat_key) {
    93→        Some(h) => h,
    94→        None => {
    95→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
    96→            return 1;
    97→        }
    98→    };
    99→
   100→    // Check if heat is stabled (cannot saddle stabled heat)
   101→    if heat.status == HeatStatus::Stabled {
   102→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   103→        return 1;
   104→    }
   105→
   106→    // Read paddock file content
   107→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   108→        Ok(content) => content,
   109→        Err(e) => {
   110→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   111→            return 1;
   112→        }
   113→    };
   114→
   115→    // Get recent steeplechase entries
   116→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   117→        firemark: args.firemark.jjrf_as_str().to_string(),
   118→        limit: 10,
   119→    }).unwrap_or_default();
   120→
   121→    // Find first actionable pace (rough or bridled)
   122→    let mut output = zjjrq_SaddleOutput {
   123→        heat_silks: heat.silks.clone(),
   124→        paddock_file: heat.paddock_file.clone(),
   125→        paddock_content,
   126→        pace_coronet: None,
   127→        pace_silks: None,
   128→        pace_state: None,
   129→        spec: None,
   130→        direction: None,
   131→        recent_work,
   132→    };
   133→
   134→    for coronet_key in &heat.order {
   135→        if let Some(pace) = heat.paces.get(coronet_key) {
   136→            if let Some(tack) = pace.tacks.first() {
   137→                match tack.state {
   138→                    PaceState::Rough | PaceState::Bridled => {
   139→                        output.pace_coronet = Some(coronet_key.clone());
   140→                        output.pace_silks = Some(tack.silks.clone());
   141→                        output.pace_state = Some(match tack.state {
   142→                            PaceState::Rough => "rough".to_string(),
   143→                            PaceState::Bridled => "bridled".to_string(),
   144→                            _ => unreachable!(),
   145→                        });
   146→                        output.spec = Some(tack.text.clone());
   147→                        if tack.state == PaceState::Bridled {
   148→                            output.direction = tack.direction.clone();
   149→                        }
   150→                        break;
   151→                    }
   152→                    _ => continue,
   153→                }
   154→            }
   155→        }
   156→    }
   157→
   158→    // Output JSON
   159→    match serde_json::to_string_pretty(&output) {
   160→        Ok(json) => {
   161→            println!("{}", json);
   162→            0
   163→        }
   164→        Err(e) => {
   165→            eprintln!("jjx_saddle: error serializing output: {}", e);
   166→            1
   167→        }
   168→    }
   169→}
   170→
   171→// ============================================================================
   172→// Parade - Display comprehensive Heat status for project review
   173→// ============================================================================
   174→
   175→/// Output format modes for parade command
   176→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   177→pub enum jjrq_ParadeFormat {
   178→    /// One line per pace: [state] silks (₢coronet)
   179→    Overview,
   180→    /// Numbered list: N. [state] silks (₢coronet)
   181→    Order,
   182→    /// Full tack text for one pace (requires --pace)
   183→    Detail,
   184→    /// Paddock + all paces with tack text (default)
   185→    #[default]
   186→    Full,
   187→}
   188→
   189→/// Arguments for parade command
   190→#[derive(Debug)]
   191→pub struct jjrq_ParadeArgs {
   192→    pub file: std::path::PathBuf,
   193→    pub firemark: Firemark,
   194→    pub format: jjrq_ParadeFormat,
   195→    pub pace: Option<String>,
   196→    pub remaining: bool,
   197→}
   198→
   199→/// Run the parade command - display comprehensive Heat status
   200→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   201→    // Validate: detail format requires --pace
   202→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   203→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   204→        return 1;
   205→    }
   206→
   207→    let gallops = match Gallops::jjrg_load(&args.file) {
   208→        Ok(g) => g,
   209→        Err(e) => {
   210→            eprintln!("jjx_parade: error: {}", e);
   211→            return 1;
   212→        }
   213→    };
   214→
   215→    let heat_key = args.firemark.jjrf_display();
   216→    let heat = match gallops.heats.get(&heat_key) {
   217→        Some(h) => h,
   218→        None => {
   219→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   220→            return 1;
   221→        }
   222→    };
   223→
   224→    match args.format {
   225→        jjrq_ParadeFormat::Overview => {
   226→            for coronet_key in &heat.order {
   227→                if let Some(pace) = heat.paces.get(coronet_key) {
   228→                    if let Some(tack) = pace.tacks.first() {
   229→                        // Skip complete/abandoned if --remaining
   230→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   231→                            continue;
   232→                        }
   233→                        let state_str = zjjrq_pace_state_str(&tack.state);
   234→                        println!("[{}] {} ({})", state_str, tack.silks, coronet_key);
   235→                    }
   236→                }
   237→            }
   238→        }
   239→        jjrq_ParadeFormat::Order => {
   240→            let mut num = 0;
   241→            for coronet_key in &heat.order {
   242→                if let Some(pace) = heat.paces.get(coronet_key) {
   243→                    if let Some(tack) = pace.tacks.first() {
   244→                        // Skip complete/abandoned if --remaining
   245→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   246→                            continue;
   247→                        }
   248→                        num += 1;
   249→                        let state_str = zjjrq_pace_state_str(&tack.state);
   250→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   251→                    }
   252→                }
   253→            }
   254→        }
   255→        jjrq_ParadeFormat::Detail => {
   256→            let pace_arg = args.pace.as_ref().unwrap();
   257→            let (coronet_key, pace) = match zjjrq_resolve_pace(heat, pace_arg) {
   258→                Some(result) => result,
   259→                None => {
   260→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}' (tried coronet and silks)", pace_arg, heat_key);
   261→                    return 1;
   262→                }
   263→            };
   264→            if let Some(tack) = pace.tacks.first() {
   265→                let state_str = zjjrq_pace_state_str(&tack.state);
   266→                println!("Pace: {} ({})", tack.silks, coronet_key);
   267→                println!("State: {}", state_str);
   268→                println!("Heat: {}", heat_key);
   269→                println!();
   270→                println!("{}", tack.text);
   271→                if let Some(ref direction) = tack.direction {
   272→                    println!();
   273→                    println!("Direction: {}", direction);
   274→                }
   275→            }
   276→        }
   277→        jjrq_ParadeFormat::Full => {
   278→            // Read paddock file content
   279→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   280→                Ok(content) => content,
   281→                Err(e) => {
   282→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   283→                    return 1;
   284→                }
   285→            };
   286→
   287→            let status_str = match heat.status {
   288→                HeatStatus::Racing => "racing",
   289→                HeatStatus::Stabled => "stabled",
   290→                HeatStatus::Retired => "retired",
   291→            };
   292→
   293→            println!("Heat: {} ({})", heat.silks, heat_key);
   294→            println!("Status: {}", status_str);
   295→            println!("Created: {}", heat.creation_time);
   296→            println!();
   297→            println!("## Paddock");
   298→            println!();
   299→            println!("{}", paddock_content);
   300→            println!();
   301→            println!("## Paces");
   302→            println!();
   303→
   304→            for coronet_key in &heat.order {
   305→                if let Some(pace) = heat.paces.get(coronet_key) {
   306→                    if let Some(tack) = pace.tacks.first() {
   307→                        // Skip complete/abandoned if --remaining
   308→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   309→                            continue;
   310→                        }
   311→                        let state_str = zjjrq_pace_state_str(&tack.state);
   312→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   313→                        println!();
   314→                        println!("{}", tack.text);
   315→                        if let Some(ref direction) = tack.direction {
   316→                            println!();
   317→                            println!("**Direction:** {}", direction);
   318→                        }
   319→                        println!();
   320→                    }
   321→                }
   322→            }
   323→        }
   324→    }
   325→
   326→    0
   327→}
   328→
   329→/// Helper to resolve pace by coronet or silks
   330→///
   331→/// First tries to parse pace_arg as a Coronet and lookup by coronet key.
   332→/// If that fails, iterates heat.paces to find a pace where tacks[0].silks matches pace_arg.
   333→/// Returns tuple of (coronet_key, pace_ref) if found.
   334→fn zjjrq_resolve_pace<'a>(
   335→    heat: &'a crate::jjrg_gallops::jjrg_Heat,
   336→    pace_arg: &str,
   337→) -> Option<(&'a String, &'a Pace)> {
   338→    // Try parsing as Coronet first
   339→    if let Ok(coronet) = Coronet::jjrf_parse(pace_arg) {
   340→        let coronet_key = coronet.jjrf_display();
   341→        if let Some((key, pace)) = heat.paces.get_key_value(&coronet_key) {
   342→            return Some((key, pace));
   343→        }
   344→    }
   345→
   346→    // Fallback: search by silks
   347→    for (coronet_key, pace) in &heat.paces {
   348→        if let Some(tack) = pace.tacks.first() {
   349→            if tack.silks == pace_arg {
   350→                return Some((coronet_key, pace));
   351→            }
   352→        }
   353→    }
   354→
   355→    None
   356→}
   357→
   358→/// Helper to convert PaceState to display string
   359→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   360→    match state {
   361→        PaceState::Rough => "rough",
   362→        PaceState::Bridled => "bridled",
   363→        PaceState::Complete => "complete",
   364→        PaceState::Abandoned => "abandoned",
   365→    }
   366→}
   367→
   368→// ============================================================================
   369→// Retire - Extract complete Heat data for archival trophy
   370→// ============================================================================
   371→
   372→/// Arguments for retire command
   373→#[derive(Debug)]
   374→pub struct jjrq_RetireArgs {
   375→    pub file: std::path::PathBuf,
   376→    pub firemark: Firemark,
   377→}
   378→
   379→/// Output structure for retire command
   380→#[derive(Serialize)]
   381→pub(crate) struct zjjrq_RetireOutput {
   382→    pub(crate) firemark: String,
   383→    pub(crate) silks: String,
   384→    pub(crate) created: String,
   385→    pub(crate) status: String,
   386→    pub(crate) paddock_file: String,
   387→    pub(crate) paddock_content: String,
   388→    pub(crate) paces: Vec<zjjrq_RetirePace>,
   389→    // TODO: steeplechase array from jjx_rein
   390→    // steeplechase: Vec<SteeplechaseEntry>,
   391→}
   392→
   393→/// Pace structure for retire output (full tack history)
   394→#[derive(Serialize)]
   395→pub(crate) struct zjjrq_RetirePace {
   396→    pub(crate) coronet: String,
   397→    pub(crate) silks: String,
   398→    pub(crate) tacks: Vec<zjjrq_RetireTack>,
   399→}
   400→
   401→/// Tack structure for retire output
   402→#[derive(Serialize)]
   403→pub(crate) struct zjjrq_RetireTack {
   404→    pub(crate) ts: String,
   405→    pub(crate) state: String,
   406→    pub(crate) text: String,
   407→    #[serde(skip_serializing_if = "Option::is_none")]
   408→    pub(crate) direction: Option<String>,
   409→}
   410→
   411→/// Run the retire command - extract complete Heat data for archival
   412→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   413→    let gallops = match Gallops::jjrg_load(&args.file) {
   414→        Ok(g) => g,
   415→        Err(e) => {
   416→            eprintln!("jjx_retire: error: {}", e);
   417→            return 1;
   418→        }
   419→    };
   420→
   421→    let heat_key = args.firemark.jjrf_display();
   422→    let heat = match gallops.heats.get(&heat_key) {
   423→        Some(h) => h,
   424→        None => {
   425→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   426→            return 1;
   427→        }
   428→    };
   429→
   430→    // Read paddock file content
   431→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   432→        Ok(content) => content,
   433→        Err(e) => {
   434→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   435→            return 1;
   436→        }
   437→    };
   438→
   439→    // Build paces array with full tack history, ordered per Heat's order array
   440→    let mut paces = Vec::new();
   441→    for coronet_key in &heat.order {
   442→        if let Some(pace) = heat.paces.get(coronet_key) {
   443→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   444→                zjjrq_RetireTack {
   445→                    ts: tack.ts.clone(),
   446→                    state: match tack.state {
   447→                        PaceState::Rough => "rough".to_string(),
   448→                        PaceState::Bridled => "bridled".to_string(),
   449→                        PaceState::Complete => "complete".to_string(),
   450→                        PaceState::Abandoned => "abandoned".to_string(),
   451→                    },
   452→                    text: tack.text.clone(),
   453→                    direction: tack.direction.clone(),
   454→                }
   455→            }).collect();
   456→
   457→            paces.push(zjjrq_RetirePace {
   458→                coronet: coronet_key.clone(),
   459→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   460→                tacks,
   461→            });
   462→        }
   463→    }
   464→
   465→    let output = zjjrq_RetireOutput {
   466→        firemark: heat_key.clone(),
   467→        silks: heat.silks.clone(),
   468→        created: heat.creation_time.clone(),
   469→        status: match heat.status {
   470→            HeatStatus::Racing => "racing".to_string(),
   471→            HeatStatus::Stabled => "stabled".to_string(),
   472→            HeatStatus::Retired => "retired".to_string(),
   473→        },
   474→        paddock_file: heat.paddock_file.clone(),
   475→        paddock_content,
   476→        paces,
   477→        // TODO: Call jjx_rein internally to get steeplechase entries
   478→    };
   479→
   480→    // Output JSON
   481→    match serde_json::to_string_pretty(&output) {
   482→        Ok(json) => {
   483→            println!("{}", json);
   484→            0
   485→        }
   486→        Err(e) => {
   487→            eprintln!("jjx_retire: error serializing output: {}", e);
   488→            1
   489→        }
   490→    }
   491→}
   492→
